// src/components/ai/AIWritingAssistant.jsx
import { useState } from "react";
import { analyzeWriting } from "../../ai/aiService";

const TONE_ICONS = {
  Professional: "👔",
  Casual: "😊",
  Technical: "⚙️",
  Inspirational: "🌟",
  Conversational: "💬",
};

const READ_COLORS = {
  Easy: "#059669",
  Medium: "#d97706",
  Advanced: "#dc2626",
};

export default function AIWritingAssistant({ title, content }) {
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [open, setOpen] = useState(false);

  const handleAnalyze = async () => {
    console.log("AI Triggered");
    console.log("Title:", title);
    console.log("Content:", content);

    if (!title.trim() || !content.trim()) {
      setError("⚠️ Please write a title and content first.");
      return;
    }

    setLoading(true);
    setError("");
    setOpen(true);

    try {
      const data = await analyzeWriting(title, content);
      console.log("AI RESULT:", data);
      setResult(data);
    } catch (e) {
      console.error("AI ERROR:", e);
      setError("❌ Analysis failed. Please check setup.");
    }

    setLoading(false);
  };

  const score = result?.score || 0;
  const scoreColor =
    score >= 8 ? "#059669" : score >= 6 ? "#d97706" : "#dc2626";

  return (
    <div style={s.wrap}>
      {/* BUTTON */}
      <button
        style={s.triggerBtn}
        onClick={handleAnalyze}
        disabled={loading}
      >
        {loading ? (
          <>
            <span style={s.spinner} /> Analysing your writing…
          </>
        ) : (
          <>
            🤖 AI Writing Assistant
          </>
        )}
      </button>

      {/* ERROR */}
      {error && <div style={s.error}>{error}</div>}

      {/* EMPTY STATE */}
      {open && !loading && !result && !error && (
        <div style={s.placeholder}>
          Click the button to analyze your writing.
        </div>
      )}

      {/* RESULT PANEL */}
      {open && result && !loading && (
        <div style={s.panel}>
          {/* HEADER */}
          <div style={s.panelHeader}>
            <span style={s.panelTitle}>✨ Writing Analysis</span>
            <button style={s.closeBtn} onClick={() => setOpen(false)}>
              ✕
            </button>
          </div>

          {/* SCORE */}
          <div style={s.metaRow}>
            <div style={s.scoreCircle}>
              <svg viewBox="0 0 36 36" style={{ width: 80, height: 80 }}>
                <circle
                  cx="18"
                  cy="18"
                  r="15.9"
                  fill="none"
                  stroke="#e2e8f0"
                  strokeWidth="2.5"
                />
                <circle
                  cx="18"
                  cy="18"
                  r="15.9"
                  fill="none"
                  stroke={scoreColor}
                  strokeWidth="2.5"
                  strokeDasharray={`${score * 10} 100`}
                  strokeLinecap="round"
                  transform="rotate(-90 18 18)"
                />
              </svg>

              <div style={s.scoreInner}>
                <span style={{ ...s.scoreNum, color: scoreColor }}>
                  {score}
                </span>
                <span style={s.scoreDen}>/10</span>
              </div>
            </div>

            {/* META */}
            <div style={s.metaRight}>
              <div style={s.metaItem}>
                <span style={s.metaLabel}>Tone</span>
                <span style={s.metaVal}>
                  {TONE_ICONS[result.tone] || "📝"} {result.tone}
                </span>
              </div>

              <div style={s.metaItem}>
                <span style={s.metaLabel}>Readability</span>
                <span
                  style={{
                    ...s.metaVal,
                    color: READ_COLORS[result.readability],
                  }}
                >
                  ● {result.readability}
                </span>
              </div>
            </div>
          </div>

          {/* INTRO */}
          {result.rewrittenIntro && (
            <div style={s.introBox}>
              <div style={s.introLabel}>💡 Suggested Opening</div>
              <p style={s.introText}>"{result.rewrittenIntro}"</p>

              <button
                style={s.copyBtn}
                onClick={() =>
                  navigator.clipboard.writeText(result.rewrittenIntro)
                }
              >
                📋 Copy
              </button>
            </div>
          )}

          {/* LISTS */}
          <div style={s.listsRow}>
            <div style={s.listBox}>
              <div style={s.listTitle}>✅ Strengths</div>
              {result.strengths?.map((item, i) => (
                <div key={i} style={s.listItem}>
                  <span style={s.greenDot} />
                  <span style={s.listText}>{item}</span>
                </div>
              ))}
            </div>

            <div style={s.listBox}>
              <div style={s.listTitle}>🔧 Improvements</div>
              {result.improvements?.map((item, i) => (
                <div key={i} style={s.listItem}>
                  <span style={s.orangeDot} />
                  <span style={s.listText}>{item}</span>
                </div>
              ))}
            </div>
          </div>

          <div style={s.poweredBy}>✨ Powered by AI</div>
        </div>
      )}
    </div>
  );
}

const s = {
  wrap: { marginTop: 10 },

  triggerBtn: {
    width: "100%",
    padding: "12px",
    background: "#1d4ed8",
    color: "#fff",
    border: "none",
    borderRadius: 10,
    fontWeight: 700,
    cursor: "pointer",
  },

  spinner: {
    width: 16,
    height: 16,
    border: "2px solid rgba(255,255,255,0.3)",
    borderTopColor: "#fff",
    borderRadius: "50%",
    animation: "spin 0.7s linear infinite",
    display: "inline-block",
  },

  error: {
    marginTop: 8,
    background: "#fee2e2",
    color: "#dc2626",
    padding: 10,
    borderRadius: 8,
    fontSize: 13,
  },

  placeholder: {
    marginTop: 10,
    padding: 12,
    background: "#f1f5f9",
    borderRadius: 8,
    fontSize: 13,
    textAlign: "center",
  },

  panel: {
    marginTop: 14,
    padding: 16,
    border: "1px solid #e5e7eb",
    borderRadius: 12,
    background: "#fff",
  },

  panelHeader: {
    display: "flex",
    justifyContent: "space-between",
    marginBottom: 12,
  },

  panelTitle: {
    fontWeight: 800,
  },

  closeBtn: {
    cursor: "pointer",
  },

  metaRow: {
    display: "flex",
    gap: 20,
    alignItems: "center",
    marginBottom: 14,
  },

  scoreCircle: { position: "relative" },

  scoreInner: {
    position: "absolute",
    inset: 0,
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    justifyContent: "center",
  },

  scoreNum: { fontSize: 18, fontWeight: 800 },
  scoreDen: { fontSize: 10 },

  metaRight: { display: "flex", flexDirection: "column", gap: 8 },

  metaItem: {},
  metaLabel: { fontSize: 10, color: "#6b7280" },
  metaVal: { fontSize: 14, fontWeight: 600 },

  introBox: {
    background: "#eff6ff",
    padding: 10,
    borderRadius: 8,
    marginBottom: 12,
  },

  introLabel: { fontSize: 12, fontWeight: 700 },
  introText: { fontSize: 13, fontStyle: "italic" },

  copyBtn: {
    marginTop: 6,
    fontSize: 12,
    cursor: "pointer",
  },

  listsRow: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: 10,
  },

  listBox: {
    border: "1px solid #e5e7eb",
    borderRadius: 8,
    padding: 10,
  },

  listTitle: { fontWeight: 700, marginBottom: 6 },

  listItem: { display: "flex", gap: 6, marginBottom: 4 },

  greenDot: {
    width: 6,
    height: 6,
    borderRadius: "50%",
    background: "green",
    marginTop: 6,
  },

  orangeDot: {
    width: 6,
    height: 6,
    borderRadius: "50%",
    background: "orange",
    marginTop: 6,
  },

  listText: { fontSize: 13 },

  poweredBy: {
    marginTop: 10,
    fontSize: 11,
    textAlign: "center",
    color: "#6b7280",
  },
};
